import React, { useState, useEffect, useCallback } from 'react';
import { api } from '../services/api'; 
import { useAuth } from '../context/AuthContext';
import { MapPin, CheckCircle, Truck, Loader2, Bike, Store, XCircle, AlertTriangle } from 'lucide-react';

const MisPedidosCliente = () => {
  const [pedidos, setPedidos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [errorConexion, setErrorConexion] = useState(false);
  const [progresoEnvio, setProgresoEnvio] = useState({}); 
  const { user } = useAuth();

  const fetchPedidos = useCallback(async () => {
    try {
      setLoading(true);
      setErrorConexion(false);
      const clienteId = user?.id || user?._id;
      if (!clienteId) return;
      
      const data = await api.getPedidosCliente(clienteId);
      setPedidos(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error("Error al obtener historial:", error);
      setErrorConexion(true);
    } finally {
      setLoading(false);
    }
  }, [user]);

  useEffect(() => {
    if (user) fetchPedidos();
  }, [user, fetchPedidos]);

  // LÓGICA DE ANIMACIÓN DE 40 SEGUNDOS
  useEffect(() => {
    const intervals = [];

    pedidos.forEach(pedido => {
      const estado = pedido.estado?.toLowerCase();
      // Solo inicia la animación si está en camino y no tiene progreso guardado
      if (estado === 'camino' && !progresoEnvio[pedido._id]) {
        let progreso = 0;
        
        // 400ms * 100 pasos = 40,000ms (40 segundos)
        const interval = setInterval(() => {
          progreso += 1;
          
          setProgresoEnvio(prev => ({ 
            ...prev, 
            [pedido._id]: progreso 
          }));

          if (progreso >= 100) {
            clearInterval(interval);
          }
        }, 400); 

        intervals.push(interval);
      }
    });

    // Limpieza de intervalos al desmontar el componente
    return () => intervals.forEach(id => clearInterval(id));
  }, [pedidos, progresoEnvio]);

  const handleCancelar = async (pedidoId) => {
    if (!window.confirm("¿Deseas cancelar este pedido?")) return;
    try {
      await api.cancelarPedido(pedidoId);
      // Al cancelar, eliminamos el progreso de la animación de ese pedido
      setProgresoEnvio(prev => {
        const nuevoProgreso = { ...prev };
        delete nuevoProgreso[pedidoId];
        return nuevoProgreso;
      });
      fetchPedidos(); 
    } catch (err) {
      alert("Error: " + err.message);
    }
  };

  if (errorConexion) return (
    <div style={msgContainer}>
      <AlertTriangle size={50} color="#ef4444" />
      <h3>Error de conexión</h3>
      <p>No se pudo conectar con el servidor.</p>
      <button onClick={fetchPedidos} style={retryButton}>Reintentar</button>
    </div>
  );

  if (loading) return (
    <div style={msgContainer}>
      <Loader2 size={40} className="animate-spin" color="#3182ce" />
      <p>Consultando pedidos...</p>
    </div>
  );

  return (
    <div style={container}>
      <h2 style={title}>Seguimiento en Vivo</h2>
      <div style={listContainer}>
        {pedidos.length === 0 ? (
          <p style={{ textAlign: 'center', color: '#94a3b8' }}>No tienes pedidos realizados.</p>
        ) : (
          pedidos.map((pedido) => {
            const estado = pedido.estado?.toLowerCase();
            // Si el estado es completado va a 100, si no, usa el progreso de la animación
            const p = progresoEnvio[pedido._id] || (estado === 'completado' ? 100 : 0);
            const puedeCancelar = estado === 'pendiente' || estado === 'proceso';

            return (
              <div key={pedido._id} style={{...orderCard, opacity: estado === 'cancelado' ? 0.6 : 1}}>
                <div style={orderHeader}>
                  <span style={dateText}>#{pedido._id?.slice(-5)}</span>
                  <span style={{...statusText, color: estado === 'cancelado' ? '#ef4444' : '#3182ce'}}>
                    {estado === 'cancelado' ? 'CANCELADO' : (p === 100 ? 'ENTREGADO' : estado.toUpperCase())}
                  </span>
                </div>

                {estado !== 'cancelado' && (
                  <div style={stepperWrapper}>
                    <div style={stepperBackground}>
                      <div style={{...stepperFill, width: `${p}%`}} />
                    </div>
                    <div style={nodesContainer}>
                      <div style={nodeGroup}>
                          <div style={{...node, backgroundColor: p >= 1 ? '#3182ce' : '#e2e8f0'}}><Store size={14} color="white" /></div>
                          <span style={nodeLabel}>Local</span>
                      </div>
                      <div style={nodeGroup}>
                          <div style={{...node, backgroundColor: p >= 50 ? '#3182ce' : '#e2e8f0'}}><Bike size={14} color="white" /></div>
                          <span style={nodeLabel}>Camino</span>
                      </div>
                      <div style={nodeGroup}>
                          <div style={{...node, backgroundColor: p >= 100 ? '#22c55e' : '#e2e8f0'}}><CheckCircle size={14} color="white" /></div>
                          <span style={nodeLabel}>Llegó</span>
                      </div>
                    </div>
                    {p > 0 && p < 100 && (
                      <div style={{...truckFloat, left: `calc(${p}% - 15px)`}}>
                        <Truck size={18} color="#3182ce" />
                      </div>
                    )}
                  </div>
                )}

                <div style={bodyCard}>
                  <h4 style={localName}>{pedido.local?.nombre || 'Local no disponible'}</h4>
                  <div style={itemsBox}>
                    {pedido.items?.map((it, i) => (
                      <div key={i} style={itemLine}>
                        <span>{it.cantidad}x {it.productoNombre}</span>
                        <span>${(it.precio * it.cantidad).toLocaleString()}</span>
                      </div>
                    ))}
                  </div>
                  <div style={priceRow}>
                    <strong>Total</strong>
                    <strong>${pedido.total?.toLocaleString()}</strong>
                  </div>
                  {puedeCancelar && (
                    <button onClick={() => handleCancelar(pedido._id)} style={cancelButton}>
                      <XCircle size={16} /> Cancelar Pedido
                    </button>
                  )}
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
};

